#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

// Linear congruential generator for random permutation
__host__ uint32_t lcg_next(uint32_t& seed) {
    seed = seed * 1664525U + 1013904223U;
    return seed;
}

__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;  // Single thread

    uint32_t idx = 0;
    asm volatile("" : : : "memory");  // Compiler barrier before timing

    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        idx = indices[idx];  // Serial dependency chain
    }

    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");  // Compiler barrier after timing

    // Anti-optimization sink - MUST cast 32-bit to 64-bit first
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = (end - start) / 10000000;  // Average cycles per access
}

int main() {
    const size_t size = 32 * 1024 * 1024;  // 32M elements = 128 MB
    const uint64_t iterations = 10000000;

    // Allocate device memory
    uint32_t* d_indices;
    uint64_t* d_cycles;

    cudaMalloc(&d_indices, size * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Create random permutation on host
    uint32_t* h_indices = (uint32_t*)malloc(size * sizeof(uint32_t));

    // Initialize with sequential indices
    for (size_t i = 0; i < size; i++) {
        h_indices[i] = i;
    }

    // Fisher-Yates shuffle with LCG
    uint32_t seed = 12345;
    for (size_t i = size - 1; i > 0; i--) {
        uint32_t j = lcg_next(seed) % (i + 1);
        std::swap(h_indices[i], h_indices[j]);
    }

    // Copy to device
    cudaMemcpy(d_indices, h_indices, size * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Run 3 trials
    uint64_t trial_cycles[3];

    for (int trial = 0; trial < 3; trial++) {
        // Warm up
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, size);
        cudaDeviceSynchronize();

        // Measure
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, size);
        cudaDeviceSynchronize();

        uint64_t h_cycles;
        cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        trial_cycles[trial] = h_cycles;
    }

    // Calculate median
    std::sort(trial_cycles, trial_cycles + 3);
    uint64_t median_cycles = trial_cycles[1];

    printf("dram_latency_cycles: %lu\n", median_cycles);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_cache_latency(volatile uint32_t* data, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;
    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < 1000000; i++) {
        idx = data[idx];
    }
    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");
    *cycles = (end - start) / 1000000;
}

int main() {
    const size_t max_size = 16 * 1024 * 1024; // 16MB max
    const size_t min_size = 128 * 1024; // 128KB min

    uint32_t* d_data;
    uint64_t* d_cycles;
    cudaMalloc(&d_data, max_size * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Generate random permutation for pointer chasing
    uint32_t* h_data = (uint32_t*)malloc(max_size * sizeof(uint32_t));
    for (size_t i = 0; i < max_size; i++) {
        h_data[i] = i;
    }

    // Fisher-Yates shuffle
    for (size_t i = max_size - 1; i > 0; i--) {
        size_t j = rand() % (i + 1);
        uint32_t temp = h_data[i];
        h_data[i] = h_data[j];
        h_data[j] = temp;
    }

    cudaMemcpy(d_data, h_data, max_size * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Sweep through different working set sizes
    size_t sizes[] = {128*1024, 256*1024, 512*1024, 1024*1024, 2*1024*1024, 
                      4*1024*1024, 6*1024*1024, 8*1024*1024, 12*1024*1024, 16*1024*1024};
    uint64_t latencies[10];

    for (int s = 0; s < 10; s++) {
        size_t current_size = sizes[s];
        measure_cache_latency<<<1, 1>>>(d_data, d_cycles, current_size);
        cudaDeviceSynchronize();

        uint64_t h_cycles;
        cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        latencies[s] = h_cycles;
    }

    // Find the inflection point (cache cliff)
    double max_increase = 0.0;
    size_t cache_size_bytes = sizes[0];

    for (int i = 1; i < 10; i++) {
        double increase = (double)latencies[i] / latencies[i-1];
        if (increase > max_increase) {
            max_increase = increase;
            cache_size_bytes = sizes[i-1];
        }
    }

    double cache_size_mb = (double)cache_size_bytes / (1024.0 * 1024.0);
    printf("l2_cache_size_mb: %.1f\n", cache_size_mb);

    free(h_data);
    cudaFree(d_data);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_boost_clock(uint64_t* cycles, float* elapsed_ms) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    const uint64_t iterations = 10000000;
    volatile float sum = 1.0f;

    asm volatile("" : : : "memory");
    volatile uint64_t start_cycles = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < iterations; i++) {
        sum = sum * 1.000001f + 1.0f;
    }

    volatile uint64_t end_cycles = clock64();
    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)sum;
    asm volatile("" : "+l"(sink64) : : "memory");

    cycles[0] = end_cycles - start_cycles;
    elapsed_ms[0] = 0.0f;
}

int main() {
    uint64_t* d_cycles;
    float* d_elapsed_ms;
    uint64_t h_cycles;
    float h_elapsed_ms;

    cudaMalloc(&d_cycles, sizeof(uint64_t));
    cudaMalloc(&d_elapsed_ms, sizeof(float));

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    measure_boost_clock<<<1, 1>>>(d_cycles, d_elapsed_ms);
    cudaEventRecord(stop);

    cudaEventSynchronize(stop);
    cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
    cudaMemcpy(&h_elapsed_ms, d_elapsed_ms, sizeof(float), cudaMemcpyDeviceToHost);

    float elapsed_time_ms;
    cudaEventElapsedTime(&elapsed_time_ms, start, stop);

    float elapsed_time_sec = elapsed_time_ms / 1000.0f;
    float frequency_mhz = (h_cycles / elapsed_time_sec) / 1000000.0f;

    printf("actual_boost_clock_mhz: %.0f\n", frequency_mhz);

    cudaFree(d_cycles);
    cudaFree(d_elapsed_ms);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}
